"""
MKT Context Commentary — Psalms chapters 86–89
Run: python3 scripts/zc-context-psalms-86-89.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)

Key decisions in this range:
- Ps 86: the only Davidic psalm in Book III (Pss 73–89); a deliberate mosaic of phrases from
  earlier psalms; v15 quotes the Exod 34:6 Sinai self-revelation formula verbatim;
  'son of your maidservant' (v16) = household-born servant, completely belonging to the master
- Ps 87: the most universalist Zion psalm; the nations enrolled as 'born in Zion' is a radical
  eschatological vision — Israel's enemies become citizens of the city of God;
  'Rahab' (v4) = poetic name for Egypt (distinct from Rahab = sea-chaos monster in Ps 89:10)
- Ps 88: the darkest psalm in the Psalter — the only one with no resolution;
  ends in darkness with no return to praise; 'Abaddon' (v11) appears only here in the Psalms;
  'Mahalath Leannoth' superscription meaning debated (possibly 'for affliction')
- Ps 89: the great Davidic covenant psalm ending Book III in crisis; almost certainly edited
  in its final form during or after the Babylonian exile (586 BCE);
  vv. 38–45 confront the apparent failure of the Davidic covenant after Jerusalem's fall;
  v52 is a Book III doxology added editorially, not part of the original psalm;
  Rahab in v10 = the chaos sea-monster (not Egypt); 'firstborn' (v27) = preeminent rank
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "86": {
    "1": '<p>Psalm 86 is the only Davidic psalm in Book III (Pss 73–89), which is otherwise dominated by Asaphite and Korahite compositions. Its placement here is probably deliberate: it forms a counterpoint of personal prayer amid the community laments of Book III. The psalm is one of the most extensively anthologized in the Psalter — nearly every phrase has a parallel in another psalm, making it a mosaic of earlier Psalter material assembled into a new personal prayer. "Poor and needy" (<em>ʿānî wĕʾebyôn</em>) — a hendiadys for those without social resources or legal protections; in the ANE legal context, the <em>ʿānî</em> (poor, lowly) and <em>ʾebyôn</em> (needy, destitute) were the specific objects of covenant protection and royal justice (Deut 15:11; Ps 72:12–13).</p>',
    "2": '<p>"Preserve my soul, for I am devoted to you" — <em>šāmĕrāh napšî kî ḥāsîd ʾānî</em>. <em>Ḥāsîd</em> (devoted one, faithful one, loyal one) is the term for one whose life is characterized by <em>ḥesed</em> — covenant loyalty. In the Psalter, the <em>ḥăsîdîm</em> are the covenant faithful who practice <em>ḥesed</em> toward both God and neighbor (Pss 4:3; 12:1; 16:10; 31:23; 37:28). The prayer appeals to the covenant as the ground for divine protection: the devotion the speaker has shown entitles him to the protection the covenant promises.</p>',
    "3": '<p>"Be gracious to me, O Lord, for I cry out to you all day long" — the appeal to divine grace (<em>ḥannênî</em>) appeals to the character of God rather than to any merit of the speaker. "All day long" (<em>kol-hayyôm</em>) emphasizes the persistence of the prayer — this is not a single petition but a sustained cry. The same continuous-prayer motif appears in Ps 55:17 (evening, morning, noon), reflecting the practice of multiple daily prayers as a discipline of covenant faithfulness.</p>',
    "4": '<p>"Gladden the soul of your servant, for to you, O Lord, I lift up my soul" — <em>ʾeśśāʾ napšî</em> (I lift up my soul) is the standard idiom for prayer orientation: the entire self directed toward God (Pss 25:1; 143:8). The request for joy (<em>śammēaḥ</em>) moves the prayer beyond deliverance to flourishing — the full wellbeing of the covenant life rather than mere survival. In the Psalter\'s theology, gladness (<em>śimḥāh</em>) in the divine presence is both a present experience (Ps 16:11) and an eschatological expectation (Ps 21:6).</p>',
    "5": '<p>"For you, O Lord, are good and forgiving, abounding in steadfast love for all who call on you" — <em>ṭôb wĕsallāḥ wĕrab-ḥesed lĕkol-qorĕʾêkā</em>. This is a compressed form of the Sinai self-revelation of Exodus 34:6–7. <em>Sallāḥ</em> (forgiving) appears as a divine attribute almost nowhere else in the OT — only here, Nehemiah 9:17, and Daniel 9:9, both explicitly reciting the Sinai formula. The phrase "for all who call on you (<em>lĕkol-qorĕʾêkā</em>)" universalizes the covenant attribute: divine ḥesed extends to all who pray, not merely to Israel.</p>',
    "6": '<p>"Give ear to my prayer, O LORD; listen to the voice of my plea for mercy" — <em>taḥănûnî</em> (my plea for mercy, my supplications) — plural, indicating sustained ongoing petition. In the later Second Temple period, this vocabulary of sustained supplication became the technical language for penitential prayer (Dan 9:3, 17–18, 20; Neh 1:6, 11; 1 Kgs 8:28–30, 38, 45, 49), linking personal distress to communal repentance.</p>',
    "7": '<p>"On the day of my trouble I call to you, for you answer me" — the confident assertion that YHWH answers prayer is built on accumulated covenant testimony: God heard in the past, therefore he will hear now. This is the same logic as the Exodus (recited as the ground for present petition in Pss 80:8–11; 81:10; 106:7–12; Neh 9:9–25).</p>',
    "8": '<p>"There is no one like you among the gods, O Lord, and no works compare to yours" — <em>ʾên kāmôkā bāʾĕlōhîm ʾadonāy</em>. The divine incomparability formula acknowledges the existence of other divine beings (<em>ʾĕlōhîm</em>) while asserting YHWH\'s absolute superiority. This is what scholars call "henotheism" — exclusive worship of YHWH alongside recognition that other divine powers exist but are incomparable. The same formula appears in Exod 15:11 ("Who is like you among the gods, O LORD?") and Ps 89:6–7 (the heavenly assembly context).</p>',
    "9": '<p>"All the nations you have made will come and bow before you, O Lord, and they will glorify your name" — the eschatological universalism of the Psalter: YHWH made all the nations, and the Creator\'s claim on his creation will ultimately be acknowledged. This forward-looking vision drives the NT\'s understanding of the Gentile mission as the fulfillment of Israel\'s worship vocation (Rom 15:9–12; Rev 15:4).</p>',
    "10": '<p>"For you are great and you do wonders; you alone are God" — <em>ʾattāh ʾĕlōhîm lĕbaddekā</em> (you alone are God). "You alone" (<em>lĕbaddekā</em>) excludes all competitors absolutely — moving beyond the incomparability formula of v. 8 to exclusivity. The NT applies this exclusive formula to the Father (John 17:3; 1 Tim 1:17) and, through the Christ-confession, reshapes it as a trinitarian claim. The "wonders (<em>niplāʾôt</em>)" are specifically the extraordinary acts of salvation-history — exodus events — that no other god performed.</p>',
    "11": '<p>"Teach me your way, O LORD, that I may walk in your truth; give me an undivided heart to reverence your name" — <em>lēb yāḥîd</em> (an undivided/unified heart) is a unique phrase. The prayer is for interior integration: a heart not divided between YHWH and other loyalties. In the Shema\'s context (Deut 6:4–5: "Love the LORD your God with all your heart"), the "whole heart" is the antithesis of the divided heart. Second Temple Judaism developed this into the concept of <em>kavanah</em> (directed intention in prayer).</p>',
    "12": '<p>"I will thank you, O Lord my God, with my whole heart; I will glorify your name forever" — the comprehensive thanksgiving vow follows from the "undivided heart" of v. 11: it is the whole heart that gives thanks. The Hebrew concept of "name" (<em>šēm</em>) encompasses the entire revealed character — to glorify the name is to publicly declare and honor the full character of YHWH.</p>',
    "13": '<p>"For your steadfast love toward me is great; you have rescued my soul from the lowest depths of Sheol" — <em>šĕʾôl taḥtîyyāh</em> (the lowest/deepest Sheol). Sheol in the OT is the underworld dwelling of the dead — not a place of punishment but of silence and separation from the divine presence (Ps 6:5; 30:9; 88:10–12). "Lowest Sheol" suggests the extreme end of the deathward direction; the divine rescue is thus a claim of exceptional salvation.</p>',
    "14": '<p>"O God, arrogant men have risen up against me; a band of ruthless men seeks my life — they do not keep you before them" — <em>zēdîm</em> (arrogant ones, the presumptuous) is a technical term in the wisdom tradition for those who presumptuously overstep covenantal boundaries (Pss 19:13; 119:21, 51, 69, 78, 85, 122; Prov 21:24). The defining characteristic: "they do not keep you before them" — the inverse of Ps 16:8 ("I have set the LORD always before me") — unaccountability before God produces violence toward humans.</p>',
    "15": '<p>"But you, O Lord, are a compassionate and gracious God, slow to anger, abounding in steadfast love and faithfulness" — <em>ʾēl raḥûm wĕḥannûn ʾerek ʾappayim wĕrab-ḥesed weʾĕmet</em>. This is the verbatim Sinai formula of Exodus 34:6 — the most foundational divine self-disclosure in the OT, repeated throughout Scripture as the bedrock description of YHWH\'s character (Num 14:18; Neh 9:17; Joel 2:13; Jonah 4:2; Ps 103:8; 145:8). The contrast with v. 14 is stark: arrogant attackers vs. the compassionate God — the prayer draws on the divine character as the most reliable ground for rescue.</p>',
    "16": '<p>"Turn to me and be gracious to me; give your strength to your servant, and save the son of your maidservant" — <em>ben-ʾāmatĕkā</em> (son of your maidservant). A servant born into the household had a stronger loyalty claim than a hired or purchased servant — the "son of the maidservant" was fully the master\'s from birth, raised entirely within the household, not a newcomer who entered service by contract. Applied to the covenant speaker, it is a claim of lifelong belonging to YHWH\'s household. The same phrase appears in Ps 116:16.</p>',
    "17": '<p>"Show me a sign of your favor, so that those who hate me will see and be ashamed" — <em>ʾôt lĕṭôbāh</em> (a sign for good, a token of favor). The request for a visible divine sign serves a social function: the "sign" will be seen by opponents who will then be "ashamed (<em>yēbōšû</em>)." In ANE honor-shame culture, visible divine vindication restored the public honor of one who had been publicly attacked. The divine comfort (<em>niḥamtānî</em>) is not merely emotional relief but public validation.</p>',
  },
  "87": {
    "1": '<p>Psalm 87 is among the Psalter\'s most remarkable theological poems — a vision of Zion as the universal birthplace of all nations. Its brevity (seven verses) belies its theological density. "His foundation is on the holy mountains" — <em>yĕsûdātô bĕharĕrê-qōdeš</em>. The divine founding (<em>yāsad</em>) of Zion is a theological claim: YHWH himself established the city as his dwelling place. "Holy mountains" (plural) may refer to the two peaks of the Jerusalem mountain complex — Zion proper and Moriah (the temple mount) — or may be a poetic plural for the sacred mountain as a whole.</p>',
    "2": '<p>"The LORD loves the gates of Zion more than all the dwelling places of Jacob" — a direct preferential statement: YHWH has chosen Jerusalem above all Israel\'s sacred sites. "Gates of Zion" — city gates were not merely architectural features but sites of legal proceedings, commerce, and civic life (Ruth 4:1–11; Prov 31:23; Amos 5:10–12). "Dwelling places of Jacob (<em>miškĕnôt yaʿăqōb</em>)" — the tent-shrines and sanctuaries distributed throughout Israel: Shiloh, Bethel, Gilgal, Beersheba. YHWH\'s exclusive preference for Jerusalem underlies the Deuteronomic centralization of worship (Deut 12:5, 11; 16:2, 6, 11).</p>',
    "3": '<p>"Glorious things are spoken of you, O city of God" — <em>nĕkabbādôt mĕdubbār bāk ʿîr hāʾĕlōhîm</em>. "Glorious things (<em>nĕkabbādôt</em>)" — things of weight, substance, honor. "City of God (<em>ʿîr hāʾĕlōhîm</em>)" — a title for Jerusalem marking it as YHWH\'s own city (Pss 46:4; 48:1, 8; Isa 60:14; Rev 3:12). The <em>Selah</em> marks a pause before the extraordinary content of v. 4.</p>',
    "4": '<p>"Among those who acknowledge me I will name Rahab and Babylon; and behold — Philistia, Tyre, and Ethiopia: \'This one was born there\'" — one of the most astonishing verses in the OT. Five nations are named — Israel\'s historic enemies: <em>Rahab</em> (the poetic name for Egypt, from the sea-monster image applied to Pharaoh in Isa 30:7; 51:9 — distinct from Rahab the chaos-dragon of Ps 89:10 and Job 9:13), Babylon, Philistia, Tyre, and Cush/Ethiopia. YHWH declares he will "name (<em>ʾazkîr</em>)" each as "born there (in Zion)" — former enemies become registered citizens of the city of God.</p>',
    "5": '<p>"Of Zion it will be said, \'This one and that one were born in her,\' and the Most High himself will establish her" — the repeated "born there/in her" is the psalm\'s refrain of astonishment. The language of being "born in" a city was the standard citizenship language of the ancient world. The psalm claims that YHWH will register foreign nations as Zion-born citizens — a spiritual re-nativity that Paul takes up in Galatians 4:26 ("the Jerusalem above is our mother") and Hebrews 12:22 ("you have come to Mount Zion, the city of the living God"). "The Most High himself (<em>wĕhûʾ yĕkônĕnehā ʿelyôn</em>)" — it is divine action, not human initiative, that brings this about.</p>',
    "6": '<p>"When the LORD records the enrollment of the peoples, he will write, \'This one was born there\'" — <em>biktōb ʿammîm</em> (in the writing/enrolling of peoples). The image is of a census or civic population register — the official record determining citizenship. In the ancient world, birth registers determined civic rights and identity; YHWH as divine scribe of nations keeps the ultimate register. Each nation is enrolled not by birth but by divine declaration. This divine enrollment anticipates Paul\'s concept of citizenship in the heavenly city (Phil 3:20) and the "book of life" in which the redeemed are registered (Rev 13:8; 20:15; 21:27).</p>',
    "7": '<p>"Singers and dancers alike say, \'All my springs of life are in you\'" — <em>wĕkol maʿăyānay bāk</em> (and all my springs are in you). The psalm closes with liturgical response from those who celebrate: singers and dancers together declare that Zion is the source of all their life-springs. "Springs (<em>maʿăyānîm</em>)" — the spring/fountain imagery appears throughout the Psalter for YHWH as the source of life (Ps 36:9: "with you is the fountain of life"; Jer 2:13: YHWH as the spring of living water). In the ancient Near East, springs were sacred — the gift of life in a dry land. All life-sources of these worshippers, including the enrolled nations, flow from this city.</p>',
  },
  "88": {
    "1": '<p>Psalm 88 stands alone in the Psalter as the one psalm with absolutely no resolution — no turn to praise, no affirmation of trust, no concluding confidence. It ends in darkness. The superscription is the most complex in the Psalter: a "Song" combined with a "Psalm of the Sons of Korah" but also attributed to "Heman the Ezrahite" (mentioned alongside Ethan in 1 Kgs 4:31 as a wise man, and as a Levitical musician in 1 Chr 15:17, 19). "Mahalath Leannoth" may mean "for affliction/humiliation" (from <em>ḥōlî</em> = sickness, and <em>ʿinnôt</em> = to afflict), though other readings have been proposed. The convergence of wisdom and lament traditions in the authorship fits: the psalm\'s wrestling with unanswered suffering is itself a wisdom problem.</p>',
    "2": '<p>"Let my prayer come before you; turn your ear toward my cry" — the standard opening petition of individual lament. The request that prayer "come before (<em>tābôʾ lĕpānêkā</em>)" God invokes the image of the royal court: the petition must be admitted through the gate into the divine presence. In Second Temple liturgy, the priests\' function included bringing worshippers\' petitions before the divine presence in the sanctuary — a liturgical intercession that guaranteed the prayer would "come before" the enthroned King.</p>',
    "3": '<p>"For my soul is saturated with troubles, and my life draws near to Sheol" — <em>śābĕʿāh bĕrāʿôt napšî</em> (my soul is full/saturated with troubles). The word <em>śābaʿ</em> (to be satisfied/full to the point of satiation) is used here negatively — filled not with good things but with evils until there is no room for more. Sheol (<em>šĕʾôl</em>) exerts a pull on the living in the Psalter\'s imagery; the severely ill or suffering person is already partially in Sheol\'s grip (Pss 18:5–6; 30:3; 116:3).</p>',
    "4": '<p>"I am reckoned among those who go down to the pit; I have become like a man with no strength at all" — <em>niḥšabttî ʿim yôrĕdê bôr</em> (I am counted/classified among those going down to the pit). The "pit (<em>bôr</em>)" is a synonym for the grave and Sheol (Pss 28:1; 30:3; 69:15; 143:7). To be "reckoned among" the dead is a social category shift — the speaker is already socially treated as a dead person (cf. Job 30:29, where Job becomes "a companion to jackals"). "No strength (<em>ʾên ʾêyāl</em>)" — the complete depletion of vitality marking the dying person.</p>',
    "5": '<p>"Like one cast loose among the dead — like the slain who lie in the grave — those you no longer remember, cut off from your hand" — the three images are cumulative: abandoned among the dead, like those killed in battle, like those whom YHWH no longer calls to mind. Divine remembering in the OT is active — to be remembered by God is to be the object of divine care and action (Gen 8:1; 30:22; Exod 2:24; 1 Sam 1:19–20); to be forgotten by God is to be outside the scope of divine providence.</p>',
    "6": '<p>"You have placed me in the lowest pit, in utter darkness, in the depths below" — the threefold descent: lowest pit (<em>bĕbôr taḥtiyyôt</em>), darkness (<em>maḥăšakkîm</em>), and the depths (<em>mĕṣôlôt</em>). These terms describe Sheol\'s geography in ANE cosmology: the underworld in perpetual darkness, in the "deep" below the cosmic waters (Job 3:5; 10:21–22; 38:17; Isa 14:15). Crucially, the speaker addresses God directly: "you have placed me" (<em>šattānî</em>) — this is not attributed to enemies or fate but to YHWH\'s own act.</p>',
    "7": '<p>"Your wrath presses down hard on me, and you have battered me with all your waves" — two divine instruments of affliction: <em>ḥĕmātĕkā</em> (your wrath) and <em>mišbārêkā</em> (your breakers, your waves). The wave imagery draws on ANE sea-chaos mythology: the divine warrior controls the chaotic sea (Ps 89:9–10; 93:3–4; 107:25–29), but here the waves are aimed at the speaker. The same imagery appears in Jonah 2:3 ("all your waves and billows have gone over me") and Lamentations 3:54.</p>',
    "8": '<p>"You have pushed my companions far away from me; you have made me repulsive to them. I am sealed in and cannot get out" — social isolation as divine action. "Made me repulsive (<em>tôʿēbôt</em>)" — the word <em>tôʿēbāh</em> (abomination, revolting thing) is the term for cultic uncleanness and moral abomination — the strongest term for what causes revulsion and exclusion. The severely ill person was in fact excluded from worship and social contact under purity laws (Lev 13–15). "Sealed in (<em>kālûʾ</em>)" — enclosed, imprisoned, unable to escape.</p>',
    "9": '<p>"My eye wastes away with grief; O LORD, I call to you every day; I spread out my hands toward you" — the wasting eye (<em>dāʾăbāh ʿênî</em>) is a physical symptom of profound grief observed throughout the Psalter (Pss 6:7; 31:9; 38:10; 69:3) and Lamentations (Lam 1:16; 2:11). "Spread out my hands (<em>šēṭaḥtî ʾēlêkā kappāy</em>)" — the physical posture of prayer in the ancient world: hands open and extended upward (1 Kgs 8:22, 38, 54; Isa 1:15; Lam 1:17; 2:19; 1 Tim 2:8). The persistence of prayer despite the suffering is the psalm\'s most remarkable feature.</p>',
    "10": '<p>"Do you perform wonders for the dead? Can the departed arise and praise you?" — the first of four rhetorical questions (vv. 10–12) that form the psalm\'s theological center. The expected answer to each is "no": Sheol in OT theology is the realm of silence, where the dead cannot praise YHWH (Pss 6:5; 30:9; 115:17; Isa 38:18–19). <em>Rĕpāʾîm</em> (the departed, the shades) — the term for the dead in Sheol (Isa 14:9; 26:14; Job 26:5; Prov 2:18; 9:18). The NT\'s answer to these questions — through resurrection — is precisely what transforms this psalm\'s horizon.</p>',
    "11": '<p>"Is your steadfast love announced in the grave? Is your faithfulness spoken of in Abaddon?" — <em>Ăbaddôn</em> (Abaddon, Destruction) appears here in the Psalms for the first time — a synonym for Sheol or the underworld (also Job 26:6; 28:22; 31:12; Prov 15:11; Rev 9:11). The name means "destruction/perdition." The two divine attributes — <em>ḥesed</em> (steadfast love) and <em>ʾĕmûnāh</em> (faithfulness) — are the Sinai attributes; the question is whether these covenant attributes extend into death\'s realm. The pre-resurrection answer is no.</p>',
    "12": '<p>"Will your wonders be known in the darkness? Will your righteousness be heard of in the land of forgetting?" — <em>ʾereṣ nĕšiyyāh</em> (the land of forgetting) — a unique and haunting phrase for Sheol. In ANE cosmology of death, Sheol was a place of oblivion — the dead neither remembered the living nor were remembered by the gods. The Mesopotamian "land of no return" (Sumerian <em>Kurnugi</em>) was similarly characterized by darkness, silence, and forgetfulness. The rhetorical implication: if you act only in the land of the living, then death is the limit of covenant relationship — make haste to act now.</p>',
    "13": '<p>"But I, O LORD, cry out to you; in the morning my prayer comes before you" — the pivot verse that moves from rhetorical despair (vv. 10–12) to continued prayer. "In the morning (<em>babbōqer</em>)" — the morning was in the Psalter the time of divine rescue and face-turning (Pss 46:5; 59:16; 90:14; Lam 3:23). The temple vigil practice involved waiting through the night for the morning announcement of divine answer (Pss 5:3; 130:5–6). The speaker continues the vigil — rising before dawn to pray — even though the divine answer has not come.</p>',
    "14": '<p>"O LORD, why do you reject my soul? Why do you hide your face from me?" — the direct accusation to YHWH: <em>lāmāh YHWH tiznaḥ napšî</em>. "Hide your face (<em>histîr pānîm</em>)" — the hidden divine face is the opposite of the Aaronic blessing ("YHWH make his face shine upon you," Num 6:25) and means divine favor withheld. The combination of rejection (<em>zānaḥ</em>) and face-hiding is the most severe description of divine absence in the Psalter. Lamentations 5:20 uses the same pair after the fall of Jerusalem.</p>',
    "15": '<p>"I have been afflicted and near death since my youth; I suffer your terrors; I am overcome" — the speaker\'s suffering is not recent but lifelong: "since my youth (<em>minneʿar</em>)" — a life defined from the beginning by suffering rather than wellness. This transforms the psalm from a situational lament into an existential one. "Your terrors (<em>ʾêmêkā</em>)" — divine terror is attributed to YHWH himself; the speaker is "overcome (<em>ʾāpûnāh</em>)" — exhausted, at the end of capacity.</p>',
    "16": '<p>"Your fierce wrath has swept over me; your terrors have destroyed me" — the two instruments from v. 7 (wrath and waves) recur: <em>ḥărônêkā</em> (your burning wrath/fierce anger) has "swept over (<em>ʿābĕrû</em>)" the speaker like a flood. "Your terrors have destroyed me (<em>bĕʿûtêkā ṣimmĕtûnî</em>)" — the verb <em>ṣāmat</em> means to cut off, silence, destroy — the annihilation of the self. The repetition of "your" throughout the psalm is theological insistence: the speaker will not attribute the suffering to impersonal forces alone — it is YHWH who is responsible, and the prayer is addressed to the one who causes the distress.</p>',
    "17": '<p>"They surround me like water all day long; they close in on me together" — the flood imagery of divine wrath (vv. 7, 16) is generalized to the sufferings that encircle the speaker. "Like water (<em>kammayim</em>) all day long" — the daily, unrelenting encirclement by suffering. The "they" who close in is ambiguous — it could be the terrors of v. 16, the afflictions of v. 15, or the enemies of v. 8 — appropriate, since total encirclement blurs the sources into a single overwhelming force.</p>',
    "18": '<p>"You have put far from me those who love me and my friends; my companions are in darkness" — the psalm ends not with praise, not with confidence, not even with petition — but with a statement of absolute desolation. The final word is "darkness (<em>maḥšāk</em>)." No psalm in the Psalter ends here. Psalm 88 alone ends without turning. The Psalter preserves this testimony without resolution because this is the experience of some who do not see rescue in this life — and that testimony is also part of covenant faith.</p>',
  },
  "89": {
    "1": '<p>Psalm 89 is attributed to "Ethan the Ezrahite" — identified in 1 Kings 4:31 with Ethan son of Mahol, among the wisest men whom Solomon surpassed, and also with the Levitical musician of 1 Chronicles 15:17, 19. It is the longest psalm in Book III (52 verses) and in its final form almost certainly reflects the Babylonian exile (586 BCE): the "but now" of v. 38 marks the abrupt transition from covenant praise to covenant lament, responding to the humiliation of the Davidic dynasty. Four movements: hymnic praise of divine faithfulness (vv. 1–4), creation theology and the heavenly council (vv. 5–14), beatitude for the covenant community (vv. 15–18), and the Davidic oracle and its apparent failure (vv. 19–52).</p>',
    "2": '<p>"For I declared, \'Your steadfast love is built to stand forever; your faithfulness is established in the heavens themselves\'" — <em>ʿôlām ḥesed yibbāneh šāmayim tākîn ʾĕmûnātĕkā</em>. The past declaration ("I said/declared") grounds the present singing: the psalmist previously confessed these truths and now brings them into confrontation with crisis. "Built to stand (<em>yibbāneh</em>)" — the construction metaphor: <em>ḥesed</em> as a structure permanently built into the fabric of reality. "Established in the heavens" — <em>ʾĕmûnāh</em> (faithfulness) has cosmic stability; it is built into the heavens themselves, not merely a human perception.</p>',
    "3": '<p>"\'I have made a covenant with my chosen one; I have sworn an oath to David my servant\'" — the divine speech begins, quoting the Davidic covenant of 2 Samuel 7:8–16 (cf. 1 Chr 17:7–14; Ps 132:11–12). The language is legal: <em>kārat bĕrît</em> (to cut a covenant — the ceremony in which animals were cut and parties passed between them, Gen 15:10, 17–18) and <em>nišbaʿtî</em> (I have sworn — the divine oath). The combination of covenant-cutting and divine oath makes the Davidic promise doubly binding. "My chosen one (<em>bĕḥîrî</em>)" — the election language applied to David (Ps 78:70).</p>',
    "4": '<p>"\'I will make your line endure forever and build your throne for every generation to come\'" — <em>leʿôlām ʾākîn zarʿekā ûbānîtî lĕdor-wādôr kissĕʾăkā</em>. The dual promise: enduring descendants (<em>zeraʿ</em>, seed/line) and an established throne. "Every generation to come (<em>lĕdor-wādôr</em>)" — the phrase describing divine faithfulness throughout the Psalter (Pss 33:11; 100:5; 103:17; 135:13) is here applied to the Davidic dynasty.</p>',
    "5": '<p>"The heavens praise your wonders, O LORD; your faithfulness is declared in the congregation of the holy ones" — the scene shifts to the heavenly court. <em>Qĕhal qĕdōšîm</em> (congregation of the holy ones) — the divine council, the assembly of heavenly beings surrounding YHWH\'s throne (1 Kgs 22:19–23; Job 1:6; 2:1; Isa 6:1–4; Dan 7:10; Rev 4–5). These "holy ones" declare YHWH\'s <em>ʾĕmûnāh</em> from within the council chamber — the highest possible testimony, since they have direct access to the divine reality.</p>',
    "6": '<p>"For who in all the heavens can be compared with the LORD? Who among the heavenly beings is like the LORD?" — the divine incomparability formula addressed specifically to the heavenly council. <em>Bĕnê ʾēlîm</em> (sons of the gods, heavenly beings) — in ANE theology, the divine council consisted of lesser divine beings subordinate to the chief deity. The Psalter\'s incomparability formula does not deny their existence but renders them incomparable to YHWH. The question is the same rhetorical device as Exodus 15:11 — the answer is always: no one.</p>',
    "7": '<p>"A God greatly feared in the assembly of the holy ones and awesome above all who surround him" — <em>bĕsôd qĕdōšîm rabbāh</em> (in the council of the holy ones, the great one). <em>Sôd</em> (the intimate council, the secret assembly) is also the term for prophetic access to the divine council in Jeremiah 23:18, 22 and Amos 3:7. YHWH is both "greatly feared (<em>neʾdar mĕʾōd</em>)" and "awesome (<em>nôrāʾ</em>)" — the root of the "numinous" experience. The council members who surround him are not rivals but subordinates in awe.</p>',
    "8": '<p>"LORD God of hosts, who is as powerful as you, LORD? Your faithfulness wraps around you on every side" — <em>YHWH ʾĕlōhê ṣĕbāʾôt</em> (LORD God of hosts/armies) — the full military title identifying YHWH as commander of the celestial armies. "Your faithfulness wraps around you (<em>ʾĕmûnātĕkā sĕbîbôtêkā</em>)" — a remarkable image: faithfulness is not an attribute YHWH displays occasionally but one that encircles him as completely as his robe or his glory. It is his defining surround.</p>',
    "9": '<p>"You govern the surging sea; when its waves rear up, you calm them" — the divine mastery over the sea (<em>yām</em>) invokes the ANE creation myth in which the chief deity defeats the chaos sea. In Canaanite mythology, Baal conquered Yam (Sea) to establish cosmic order; in Babylonian mythology, Marduk defeated Tiamat (the salt-water chaos). Psalm 89 appropriates this cosmic combat imagery for YHWH: he does not merely defeat the sea once but continually "governs (<em>mōšēl</em>)" it and "calms (<em>tĕšabbĕḥēm</em>)" its waves.</p>',
    "10": '<p>"You crushed Rahab like a slaughtered carcass; with your mighty arm you scattered your enemies" — <em>Rahab</em> here is the chaos sea-monster (distinct from Rahab = Egypt in v. 4), the primordial serpentine creature representing chaotic sea in ANE mythology (Job 9:13; 26:12; Isa 51:9; Ps 74:13–14). "Crushed like a slaughtered carcass" — the chaos creature is treated like a sacrificed animal, its body displayed in defeat. Isaiah 51:9 uses the same imagery as the basis for praying that God will do again what he did in creation. The God who crushed the chaos monster is the same God who rules the Davidic covenant.</p>',
    "11": '<p>"The heavens belong to you; the earth also is yours; you founded the world and everything in it" — the comprehensive territorial claim follows the chaos-victory: because YHWH defeated chaos and established order, he owns everything. "You founded (<em>yāsadtā</em>) the world" — the foundational act of ordering creation (Ps 24:1–2; 104:5; Prov 8:29; Isa 48:13; 51:13, 16). This cosmic ownership is the basis for the territorial claims in the Davidic oracle (v. 25: "I will extend his dominion to the sea").</p>',
    "12": '<p>"North and south — you created them; Tabor and Hermon sing for joy in your name" — the four compass directions and two prominent mountains represent the totality of geographical space. Tabor (the isolated mountain in the Jezreel Valley, 575m, site of Barak\'s victory in Judg 4:6–16) and Hermon (the great northern peak of the Anti-Lebanon range, 2,814m, snowcapped, marking the northern limit of Israel\'s territory) represent the geographic extent of the land. The mountains "sing for joy (<em>yārōnnû</em>)" — personified worship of their creator.</p>',
    "13": '<p>"Your arm is mighty; your hand is strong; your right hand is raised high" — three body-metaphors for divine power: <em>zĕrôaʿ</em> (arm, the instrument of power), <em>yād</em> (hand, the instrument of action), and <em>yĕmîn</em> (right hand, the instrument of favor and victory). The "right hand raised high (<em>tārûm yĕmînĕkā</em>)" echoes Exodus 15:6, 12 — the victory at the Reed Sea. The psalmist moves from creation theology back to salvation-history: the arm that created is the arm that saves.</p>',
    "14": '<p>"Righteousness and justice are the foundation of your throne; steadfast love and faithfulness lead the way before you" — <em>ṣedeq ûmišpāṭ mĕkôn kissĕʾekā ḥesed weʾĕmet yĕqaddĕmû pānêkā</em>. The four divine attributes in pairs: <em>ṣedeq</em> (righteousness) and <em>mišpāṭ</em> (justice) as the structural foundation (<em>mĕkôn</em>) of the divine throne; <em>ḥesed</em> (steadfast love) and <em>ʾĕmet</em> (faithfulness) as the divine advance-guard who walk before the enthroned king. Psalm 97:2 uses identical language; this couplet becomes the most succinct statement of YHWH\'s governing character in the Psalter.</p>',
    "15": '<p>"Blessed is the people who know the joyful shout; they walk, LORD, in the light of your face" — <em>tĕrûʿāh</em> (joyful shout, battle cry, trumpet blast) is the multi-purpose word for the blast of the shofar at the new year, at the jubilee (Lev 25:9), at the ark\'s movement (Num 10:5–9), and in battle (Num 31:6; Josh 6:5, 20). The "people who know the tĕrûʿāh" are those who participate in this full range of covenant life — worship, sacred time, and holy war together. "Light of your face (<em>bĕʾôr-pānêkā</em>)" — to walk in the light of the divine face is to live within the sphere of divine favor (Num 6:25–26; Ps 4:6; 31:16; 67:1).</p>',
    "16": '<p>"They rejoice in your name all day long and are lifted up by your righteousness" — the covenant community\'s joy is located in the divine name (all of YHWH\'s revealed character) rather than in circumstances. "Lifted up (<em>yārûmû</em>) by your righteousness (<em>bĕṣidqātĕkā</em>)" — the passive elevation: the community does not raise itself through its own accomplishment but is raised by the divine righteousness that acts on their behalf.</p>',
    "17": '<p>"For you are the splendor of their strength; by your favor our strength is raised high" — <em>tipeʾret ʿuzzāmô ʾattāh</em> (you are the glory/splendor of their strength). The community\'s strength has glory only because YHWH is its source. "By your favor (<em>birṣônĕkā</em>)" — <em>rāṣôn</em> (divine favor, goodwill, delight) is the condition without which nothing flourishes; the same word describes the acceptable sacrifice (Lev 1:3; 22:20) and divine approval of righteous living (Prov 8:35; 12:22; 16:7).</p>',
    "18": '<p>"For our shield belongs to the LORD; our king is the Holy One of Israel" — the "Holy One of Israel" is Isaiah\'s characteristic divine title (appearing ~26 times in Isaiah alone — 1:4; 5:19; 10:20; 12:6; 17:7; 29:19; 30:11–12; 31:1; 37:23; 40:25; 41:14; etc.) and here the king is associated with this epithet — the Davidic king as the representative of YHWH the Holy One, whose protection of the king extends to the whole community.</p>',
    "19": '<p>"You spoke in a vision to your faithful servants and said: \'I have given help to a warrior; I have raised up a young man chosen from among the people\'" — the divine oracle transitions from cosmic theology (vv. 5–18) to Davidic history. "In a vision (<em>beḥāzôn</em>)" to "your faithful servants (<em>ḥăsîdêkā</em>)" — the plural may refer to Nathan (2 Sam 7), Samuel (1 Sam 16), or the prophetic tradition generally. "A warrior (<em>gibbôr</em>)" — the term for the mighty warrior (Gen 6:4; Josh 1:14; 2 Sam 23:8–39, the list of David\'s mighty men). "Chosen from among the people" — David\'s election was from the common people, not from the nobility or priestly class.</p>',
    "20": '<p>"\'I have found David my servant; with my holy oil I have anointed him\'" — the anointing of David (1 Sam 16:1–13, where Samuel anointed David at YHWH\'s direction; also 2 Sam 2:4; 5:3). "With my holy oil (<em>bĕšemen qodšî</em>)" — the anointing oil was a sacred substance made according to Exodus 30:22–33, reserved exclusively for consecrating the tabernacle, its furnishings, Aaron, and his sons. Extending this sacred anointing to the king makes the Davidic anointing a priestly-level consecration. The word <em>māšîaḥ</em> (anointed, Messiah) derives directly from this anointing act.</p>',
    "21": '<p>"\'My hand will uphold him steadily; my arm will give him strength\'" — the two body-metaphors of divine support: the hand (<em>yād</em>) that "upholds steadily (<em>tikôn</em>)" and the arm (<em>zĕrôaʿ</em>) that strengthens. The same arm-and-hand imagery used for YHWH\'s creation power (v. 13) and exodus victory is now directed toward the king — the divine warrior\'s power applied to sustaining the royal covenant partner.</p>',
    "22": '<p>"\'No enemy will overpower him; no wicked person will oppress him\'" — the double promise of covenant protection: no external enemy (<em>ʾôyēb</em>) will "outwit/overpower" him, and no wicked person (<em>ben-ʿawlāh</em>, son of wickedness/lawlessness) will "oppress" him. These promises are explicitly political-military: the king\'s enemies will not succeed. The confrontation of these promises with the crisis of vv. 38–45 — where enemies do overpower the anointed — is the psalm\'s central theological tension.</p>',
    "23": '<p>"\'I will shatter his enemies before his eyes and defeat all who hate him\'" — the divine warrior fighting on behalf of the king: <em>kattōtî mipānāyw ṣārāyw</em> (I will crush his enemies before his face). The king witnesses the divine victory personally — the enemies are defeated in the royal presence. This mirrors the Exodus pattern (YHWH fighting for Israel before the eyes of Pharaoh, Exod 14:13). The king\'s victories are simultaneously acts of divine proclamation — the nations see that YHWH fights for David.</p>',
    "24": '<p>"\'My faithfulness and steadfast love will be with him; through my name his strength will be raised high\'" — <em>ʾĕmûnātî wĕḥasdî ʿimmô</em> (my faithfulness and my ḥesed will be with him). The two Sinai attributes (from Exod 34:6) travel with the king as companions — the same personification as in v. 14 where they "walk before" YHWH. "Through my name (<em>ûbišmî</em>) his strength is raised high" — not through the king\'s own name but through YHWH\'s name as the source of royal power.</p>',
    "25": '<p>"\'I will extend his dominion to the sea and his right hand over the rivers\'" — <em>wĕśamtî bayyām yādô ûbanĕhārôt yĕmînô</em>. The expansion of Davidic dominion "to the sea" and "over the rivers" employs the Psalter\'s formula for universal sovereignty (Ps 72:8: "may he have dominion from sea to sea, and from the River to the ends of the earth"). In the ANE, the dominion formula "from sea to sea" was used for empires (Egypt, Assyria, Babylon) claiming universal sovereignty.</p>',
    "26": '<p>"\'He will call out to me, "You are my Father, my God, and the Rock who saves me!\'" — <em>hûʾ yiqrāʾ-lî ʾābî ʾattāh ʾēlî ûṣûr yĕšûʿātî</em>. The Davidic king\'s address to YHWH as "my Father (<em>ʾābî</em>)" establishes a filial relationship. In ANE royal ideology, the king was understood as the divine son (Ps 2:7: "You are my Son; today I have begotten you"). The NT applies this directly to Christ: "I will be a father to him, and he will be my son" (2 Sam 7:14 / Heb 1:5). "Rock who saves me (<em>ṣûr yĕšûʿātî</em>)" — the geological image of invincible refuge combined with the active concept of salvation.</p>',
    "27": '<p>"\'I will appoint him as my firstborn, the highest of all the kings of the earth\'" — "Firstborn (<em>bĕkôr</em>)" in the OT is not merely birth order but rank and inheritance privilege: the firstborn received the double portion and covenantal precedence (Gen 25:29–34; 27; 48:13–20). Applied to the king, "firstborn" means the preeminent one, highest in rank among all earthly kings. In the Exodus narrative, Israel itself is YHWH\'s "firstborn son" (Exod 4:22–23) — the king concentrates in himself the royal identity of the whole nation. The NT applies this title to Christ as the firstborn over all creation (Col 1:15; Heb 1:6; Rev 1:5).</p>',
    "28": '<p>"\'I will maintain my steadfast love for him forever, and my covenant with him will be secure\'" — <em>lĕʿôlām ʾešmor-lô ḥasdî ûbĕrîtî neʾĕmenet lô</em>. "I will maintain (<em>šāmar</em>) my ḥesed" — <em>šāmar</em> (to guard, keep, maintain) indicates active preservation, not passive continuation. The covenant (<em>bĕrît</em>) is "secure/reliable (<em>neʾĕmenet</em>)" — the same root as <em>ʾĕmûnāh</em> (faithfulness). The promise is self-grounding: the covenant is reliable because YHWH is faithful.</p>',
    "29": '<p>"\'His line will continue forever, and his throne will last as long as the heavens above\'" — the double "forever": <em>zarʿô lĕʿôlām</em> (his line/seed forever) and <em>kissĕʾô kidmê šāmāyim</em> (his throne like the days of the heavens — enduring as long as the heavens exist). The "days of the heavens" is the Psalter\'s highest duration marker. The Davidic throne is given this cosmic duration — the claim that is then confronted by the throne\'s apparent overthrow in vv. 38–45.</p>',
    "30": '<p>"\'If his descendants abandon my instruction and refuse to live by my rulings\'" — the conditional clause introducing the psalm\'s hinge. The covenant is unconditional in its ultimate purpose (vv. 28–29) but conditional in its immediate application to individual kings. This is the structure of the Mosaic-Davidic covenant: the unconditional promise (YHWH will maintain ḥesed forever, vv. 28, 33) coexists with conditional discipline (vv. 30–32). The distinction matters for reading the exile: the exile is covenant discipline, not covenant termination (2 Sam 7:14–16).</p>',
    "31": '<p>"\'if they break my decrees and fail to keep my commandments\'" — the four standard vocabulary items of Deuteronomy for the covenant law body in vv. 30–31: <em>tôrāh</em> (instruction), <em>mišpāṭîm</em> (rulings/judgments), <em>ḥuqqôt</em> (decrees), and <em>miṣwôt</em> (commandments). The comprehensive repetition leaves no loophole: failure in any part of the covenant instruction system triggers the discipline clause.</p>',
    "32": '<p>"\'then I will punish their rebellion with a rod and their sin with blows\'" — the discipline is covenant chastisement (<em>musar</em>, correction through suffering) rather than covenant termination. <em>Šēbeṭ</em> (rod — the instrument of discipline in Prov 13:24; 22:15; 23:13–14) and <em>nĕgāʿîm</em> (blows) are the disciplinary tools of the divine parent correcting the child. The Babylonian exile could be understood through this frame: not YHWH abandoning the Davidic covenant but disciplining covenant-breaking kings through the "rod" of imperial invasion (Lam 3:1: "I am the man who has seen affliction by the rod of his wrath").</p>',
    "33": '<p>"\'But I will not withdraw my steadfast love from him or betray my faithfulness\'" — <em>wĕḥasdî lōʾ-ʾāpîr mēʿimmô wĕlōʾ-ʾăšaqqēr beʾĕmûnātî</em>. The "but (<em>wĕ</em>)" is the pivotal word: the discipline is real (vv. 30–32), but the withdrawal of <em>ḥesed</em> is absolutely excluded. "Betray my faithfulness (<em>ʾăšaqqēr beʾĕmûnātî</em>)" — <em>šāqar</em> (to act deceitfully, to lie, to break faith) is what YHWH refuses to do to his own <em>ʾĕmûnāh</em>: divine faithfulness cannot be betrayed by its own source. This verse is the irreducible unconditional core of the Davidic covenant.</p>',
    "34": '<p>"\'I will not break my covenant or change what I have spoken\'" — <em>lōʾ-ʾăḥallēl bĕrîtî ûmôṣāʾ śĕpātay lōʾ ʾăšanneh</em>. "Break my covenant (<em>ḥillēl bĕrîtî</em>)" — the same verb used for the betraying companion who "broke his covenant" in Psalm 55:20 — what the human covenant-breaker did, YHWH refuses to do. "Change what I have spoken (<em>ʾăšanneh</em>)" — YHWH\'s spoken word is irrevocable: Numbers 23:19 uses the same language ("God is not a man, that he should lie, or a son of man, that he should change his mind").</p>',
    "35": '<p>"\'I have sworn by my own holiness once and for all; I will not deceive David\'" — <em>nišbaʿtî bĕqodšî</em> (sworn by my holiness). The most absolute oath YHWH can make: sworn by his own essential character rather than by anything external. In Amos 4:2 and 6:8, YHWH swears "by his holiness" and "by himself" (<em>bĕnapšô</em>) — there is nothing higher by which he can swear (Heb 6:13). YHWH\'s oath by his holiness makes his promise to David as reliable as the divine character itself.</p>',
    "36": '<p>"\'His descendants will endure forever; his throne will last as long as the sun shines before me\'" — the sun (<em>šemeš</em>) as the most reliable of natural markers of permanence: "as long as the sun shines before me (<em>lĕpānay</em>)." This image will be transcended in the eschatological vision where the sun is no longer needed (Isa 60:19–20; Rev 21:23; 22:5) — but within the temporal order, the sun\'s permanence is the highest natural analogy for the Davidic promise.</p>',
    "37": '<p>"\'Like the moon it will be established forever, that faithful witness set in the heavens.\' Selah" — <em>kĕyārēaḥ yikkôn ʿôlām wĕʿēd baššāḥaq neʾĕmān</em>. The moon (<em>yārēaḥ</em>) complements the sun: both celestial bodies are "established (<em>yikkôn</em>)" — the same <em>kûn</em> root used for the founding of YHWH\'s throne (v. 14). "That faithful witness set in the heavens" — the moon is personified as a reliable witness to the covenant promise, cycling its testimony every month. <em>Selah</em> marks the end of the divine oracle and the beginning of the devastating reversal of vv. 38–45.</p>',
    "38": '<p>"But now you have cast off and rejected him; you are enraged against your anointed king" — <em>wĕʾattāh zānaḥtā ûtimʾas hittaʿbartā ʿim-mĕšîḥekā</em>. The pivot: "but now (<em>wĕʾattāh</em>)." Three verbs of divine rejection applied to the king: "cast off (<em>zānaḥtā</em>), rejected (<em>timʾas</em>), enraged (<em>hittaʿbartā</em>)." The word <em>mĕšîḥekā</em> (your anointed, your Messiah) is one of the most theologically charged terms in the OT. That the very one YHWH anointed and swore to uphold is now apparently abandoned is the psalm\'s agonizing contradiction. This section (vv. 38–45) almost certainly reflects the fall of Jerusalem (586 BCE) and the humiliation of Zedekiah or Jehoiachin.</p>',
    "39": '<p>"You have repudiated the covenant with your servant; you have thrown his crown into the dust" — <em>nippartā bĕrît ʿabdekā</em> (you have broken/violated the covenant of your servant). The covenant declared inviolable in vv. 28–35 is now described as broken — not by the king but by YHWH himself. This is the lament\'s most audacious claim: that God has done what he swore he would never do. "Thrown his crown (<em>nizzĕrô</em>) into the dust" — the crown symbolizing royal dignity is cast down; the humiliated king without crown is the anti-image of the enthroned sovereign of vv. 19–37.</p>',
    "40": '<p>"You have broken down all his walls and reduced his fortifications to rubble" — the city walls of Jerusalem are in view. The Babylonian siege and destruction of Jerusalem (586 BCE) literally broke down the city walls (2 Kgs 25:10; Jer 52:14; Lam 2:7–8). The psalmist speaks this in terms of YHWH\'s own action: not merely the Babylonians attacked, but YHWH "broke down (<em>pāraṣtā</em>)" the walls. Lamentations consistently makes the same theological attribution: "The Lord has done what he planned; he has fulfilled his threat" (Lam 2:17).</p>',
    "41": '<p>"All who pass by strip him of what he has; he has become a mockery to his neighbors" — "all who pass by (<em>kol-ʿōbĕrê derek</em>)" plunder him — the same phrase as Lamentations 1:12 ("Is it nothing to you, all you who pass by?"). In ANE culture, the humiliated king who could not protect his city was subject to the contemptuous mockery of neighboring states. "Mockery (<em>ḥerpāh</em>)" — shame, reproach — the most damaging social judgment in an honor-shame culture: honor destroyed by public failure.</p>',
    "42": '<p>"You have strengthened the hand of his enemies; you have let all who hate him celebrate" — the two divine actions invert the promises: YHWH swore to "shatter his enemies before his eyes" (v. 23) but now instead strengthens those enemies\' hands. The enemies\' celebration (<em>śimmaḥtāh</em>) inverts the community\'s joy (v. 16: "they rejoice in your name"). Every promise has been reversed.</p>',
    "43": '<p>"You have blunted his sword in battle and failed to hold him up when he fought" — <em>ʾap-tāšîb ṣûr ḥarbô</em> (you have turned back the edge of his sword). The blunted sword — the weapon that cannot cut — is the image of military impotence. "Failed to hold him up (<em>lōʾ hăqēmôtô</em>)" — the same verb <em>qûm</em> (to stand up) used for YHWH upholding the king (v. 21: "my arm will give him strength") now negated. The promises of vv. 21–23 are systematically inverted in vv. 38–45.</p>',
    "44": '<p>"You have stripped away his glory and hurled his throne down to the ground" — <em>hišbattā miṭṭohŏrô</em> (you caused his splendor to cease). The "splendor/purity (<em>ṭōhar</em>)" of the king — the radiant glory of the anointed ruler — has been removed. "Hurled his throne down to the ground (<em>kissĕʾô lāʾāreṣ miggartāh</em>)" — the throne cast to earth is the anti-image of the throne "established in the heavens" (v. 29). The cosmic height of the Davidic promise has become the cosmic depth of its apparent reversal.</p>',
    "45": '<p>"You have shortened the days of his prime and wrapped him in shame" — <em>qiṣṣartā yĕmê ʿălûmāyw</em> (you shortened the days of his youth/prime). The Davidic promise included long days (v. 36: enduring "as long as the sun") but the king\'s actual years have been cut short — whether by premature death, imprisonment (Jehoiachin\'s thirty-seven years in Babylonian prison, 2 Kgs 25:27–30), or exile. "Wrapped him in shame (<em>heʿṭîtāhû bûšāh</em>)" — clothed in shame as if in a garment (Ps 109:29).</p>',
    "46": '<p>"How long, O LORD? Will you hide yourself away forever? How long will your anger blaze like fire?" — <em>ʿad-māh YHWH tissātēr lāneṣaḥ</em>. The classic lament question "<em>ʿad māh</em>" (how long?) appears throughout the Psalter (Pss 6:3; 13:1–2; 35:17; 74:10; 79:5; 80:4; 82:2; 94:3) and becomes a formulaic expression of the intensity of suffering under divine silence. "Hide yourself away (<em>tissātēr</em>) forever (<em>lāneṣaḥ</em>)" — the divine hiddenness feared as permanent: is the exile eternal?</p>',
    "47": '<p>"Remember how short my span of life is! For what emptiness you have made all the children of man!" — <em>zĕkor-meh ḥeled</em> (remember what a span, how brief). <em>Ḥeled</em> (lifespan, duration of life) — the psalmist appeals to human brevity as an argument for divine urgency. The appeal "remember (<em>zĕkor</em>)" activates the covenant vocabulary: divine remembering is active care (Gen 8:1; Exod 2:24; Ps 98:3). "For what emptiness (<em>mah-šāwʾ</em>) you have made all the children of man" — the <em>šāwʾ</em> (vanity, emptiness) of Ecclesiastes applied to human existence without divine faithfulness.</p>',
    "48": '<p>"What man can go on living and never see death? Who can rescue his life from the grip of the grave?" — the mortality argument for divine urgency. In the Psalter\'s pre-resurrection theology, death is the universal human fate and the limit of covenant experience. The argument is not despair but urgency: if you are going to act, act now, before death removes the possibility. The same logic underlies Hezekiah\'s prayer (Isa 38:18–19: "For Sheol does not thank you... the living — they praise you, as I do today").</p>',
    "49": '<p>"Lord, where is your steadfast love of old, which in your faithfulness you swore to David?" — <em>ʾayyēh ḥăsādêkā hārîʾšōnîm ʾadonāy ʾăšer nišbaʿtā lĕdāwid beʾĕmûnātekā</em>. The covenant vocabulary accumulated through the psalm (<em>ḥesed</em>, <em>ʾĕmûnāh</em>, <em>nišbaʿtā</em>) is now turned into a lament question. "Where (<em>ʾayyēh</em>)?" — the word of anguished searching for God\'s apparent absence (Pss 42:3, 10; 79:10; 115:2; Joel 2:17). "You swore (<em>nišbaʿtā</em>) in your faithfulness" — the divine oath of v. 3 is thrown back at God as evidence of the crisis.</p>',
    "50": '<p>"Remember, Lord, the mocking your servants endure — how I bear in my heart the taunts of all those nations" — the final appeal moves from the individual king to the corporate community: "your servants (<em>ʿăbādêkā</em>)" endure <em>ḥerpāh</em> (mocking, reproach). "Bear in my heart (<em>bĕḥêqî</em>) — in my bosom" — the mockery has been internalized. In ANE culture, the taunting of a defeated people\'s God — "where is their God?" (Ps 79:10; 115:2; Joel 2:17) — was among the most theologically painful experiences, implying that YHWH was either unable or unwilling to keep his covenant promises.</p>',
    "51": '<p>"with which your enemies, LORD, have taunted, mocking every step of your anointed king" — <em>ʾăšer ḥērĕpû ʾôyĕbêkā YHWH ʾăšer ḥērĕpû ʿiqĕbôt mĕšîḥekā</em>. The taunt is twice described as coming from "your enemies, LORD" — the enemies of the psalmist are simultaneously enemies of YHWH. "Mocking every step (<em>ʿiqĕbôt</em>) of your anointed" — <em>ʿāqēb</em> (heel, footstep) — the enemies trace the heel-prints of the anointed king, mocking his every movement and retreat. The Messianic title (<em>mĕšîḥekā</em>) at the psalm\'s close links the present crisis to the entire Davidic promise: it is the Messiah himself who is mocked.</p>',
    "52": '<p>Verse 52 is not part of Psalm 89 but the closing doxology of Book III of the Psalter, added by the editors who compiled the five-book Psalter structure (Pss 1–41, 42–72, 73–89, 90–106, 107–150): "Blessed be the LORD forever! Amen and Amen." Each of the five books ends with a doxology (Ps 41:13; 72:18–19; 89:52; 106:48; 150:6). The placement of this doxology at the end of Book III is striking: the preceding 51 verses end in lament and crisis, and then the doxology is added — not as a resolution but as a frame that surrounds the crisis with ongoing praise. The Psalter\'s editorial structure insists on blessing YHWH even in the midst of unresolved covenant crisis — the doxology is an act of faith that transcends the psalm\'s own ending.</p>',
  }
}

# INTENT: mkt-context for Psalms 86–89 — a Davidic mosaic prayer (Ps 86, with Exod 34:6 verbatim),
#   the most universalist Zion psalm (Ps 87, nations enrolled as Zion-born citizens),
#   the Psalter's only unresolved lament (Ps 88, ending in darkness), and
#   the great Davidic covenant psalm in crisis (Ps 89, likely exilic).
# CHANGE? If mkt-context/psalms.json structure changes, update load_comm/save_comm source string.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/psalms.json'));
#   print('89 v38:', d.get('89',{}).get('38','MISSING')[:80])"

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Psalms mkt-context: {len(existing)} chapters, {total} verse entries total')
    print('Psalms 86–89 mkt-context written.')

if __name__ == '__main__':
    main()
